import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-healthcare-project',
  webhookToken: process.env.VEX_WEBHOOK_TOKEN
});

// n8n webhook receives AI agent output
app.post('/vex-healthcare-guardrail', async (req, res) => {
  const { aiOutput, patientContext, workflowId } = req.body;

  const result = await vex.evaluate({
    inputs: {
      aiOutput,
      patientContext,
      workflowExecutionId: workflowId
    },
    rules: [
      {
        name: 'block-phi-exposure',
        type: 'regex',
        pattern: /\b(?:SSN|MRN|DOB|PATIENT\s+ID)[^\w]*(\d{3}-?\d{2}-?\d{4}|\d{8,15})|\b[A-Z][a-z]+\s[A-Z][a-z]+\s(?:MD|DO|RN|NP)\b/i,
        action: 'block',
        severity: 'critical',
        message: 'PHI detected - transmission blocked per HIPAA'
      },
      {
        name: 'validate-medical-recommendations',
        type: 'prompt',
        prompt: `Review this AI medical recommendation for safety: ${aiOutput}`,
        criteria: {
          safetyScore: { min: 0.9 },
          hallucinationRisk: { max: 0.1 }
        },
        action: 'block',
        severity: 'high'
      }
    ]
  });

  if (result.status === 'blocked') {
    await vex.logIncident({
      workflowId,
      ruleId: result.violatedRule,
      context: { patientContext, aiOutput: '[REDACTED]' },
      regulation: 'HIPAA'
    });
  }

  res.json({ safeToProceed: result.status === 'pass', auditId: result.auditId });
});

import { Vex } from '@vex_dev/sdk';

const MAX_EXECUTIONS = 5;

const vex = new Vex({ projectId: 'healthcare-n8n' });

app.post('/vex-recursion-guard', async (req, res) => {
  const { workflowId, executionCount, triggerChain } = req.body;

  const result = await vex.evaluate({
    inputs: { workflowId, executionCount, triggerChain },
    rules: [
      {
        name: 'detect-recursion',
        type: 'custom',
        condition: `executionCount > ${MAX_EXECUTIONS} || triggerChain.includes(workflowId)`,
        action: 'block',
        severity: 'high',
        message: `Recursive execution detected (${executionCount}x). HIPAA compute limits exceeded.`
      },
      {
        name: 'validate-trigger-legitimacy',
        type: 'regex',
        pattern: /patient-emergency|critical-alert|triage-priority/i,
        action: 'allow',
        severity: 'medium',
        message: 'Emergency trigger validated'
      }
    ]
  });

  res.json({
    allowExecution: result.status === 'pass',
    executionLimit: MAX_EXECUTIONS,
    currentCount: executionCount
  });
});

import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ projectId: 'n8n-healthcare' });

app.post('/vex-memory-guardrail', async (req, res) => {
  const { memoryContext, currentPatientId, timestamp, conversationId } = req.body;

  const contextAgeHours = (Date.now() - new Date(timestamp).getTime()) / (1000 * 60 * 60);

  const result = await vex.evaluate({
    inputs: {
      memoryContext,
      currentPatientId,
      contextAgeHours,
      conversationId
    },
    rules: [
      {
        name: 'stale-context-block',
        type: 'custom',
        condition: 'contextAgeHours > 24',
        action: 'block',
        severity: 'high',
        message: 'Stale patient context (>24h old) - FDA 21 CFR Part 11 audit trail required'
      },
      {
        name: 'patient-id-mismatch',
        type: 'custom',
        condition: `memoryContext.patientId !== currentPatientId`,
        action: 'block',
        severity: 'critical',
        message: 'Patient context mismatch - potential wrong patient data injection'
      },
      {
        name: 'phi-memory-leak',
        type: 'regex',
        pattern: /(SSN|medical\s+record\s+number|date\s+of\s+birth)\s*[:=]\s*[^\s]+/i,
        action: 'block',
        severity: 'critical'
      }
    ]
  });

  res.json({
    contextValid: result.status === 'pass',
    contextAgeHours,
    auditTrailId: result.auditId
  });
});
